import{_ as t,o as s,c as n,a as i}from"./chunks/framework.8tiMeCK-.js";const u=JSON.parse('{"title":"2.3  Netlink Message Header","description":"","frontmatter":{},"headers":[],"relativePath":"en/notes/linux_kernel_networking/ch02_3.md","filePath":"en/notes/linux_kernel_networking/ch02_3.md","lastUpdated":null}'),a={name:"en/notes/linux_kernel_networking/ch02_3.md"};function l(o,e,r,d,c,h){return s(),n("div",null,[...e[0]||(e[0]=[i(`<h1 id="_2-3-netlink-message-header" tabindex="-1">2.3 Netlink Message Header <a class="header-anchor" href="#_2-3-netlink-message-header" aria-label="Permalink to &quot;2.3  Netlink Message Header&quot;">​</a></h1><p>In the previous section, we saw how the kernel places messages into the send queue — tracing the call chain from <code>rtnetlink</code> all the way to the generic <code>netlink</code> module.</p><p>But that&#39;s like knowing how a post office sorts mail without ever looking at the envelopes. Netlink communication is fundamentally about packets, and these packets aren&#39;t arbitrary — they must follow the rules laid out in RFC 3549 (&quot;Linux Netlink as an IP Services Protocol&quot;).</p><p>In this section, instead of tracing function calls, we tear open a packet and examine the raw bytes.</p><h3 id="header-structure" tabindex="-1">Header Structure <a class="header-anchor" href="#header-structure" aria-label="Permalink to &quot;Header Structure&quot;">​</a></h3><p>Every Netlink packet must begin with a fixed 16-byte header. This header is defined in the kernel as <code>struct nlmsghdr</code>, located in <code>include/uapi/linux/netlink.h</code>:</p><div class="language-c vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">struct</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> nlmsghdr</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    __u32 nlmsg_len;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   /* 消息总长度（包含头部） */</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    __u16 nlmsg_type;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  /* 消息类型 */</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    __u16 nlmsg_flags;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> /* 标志位 */</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    __u32 nlmsg_seq;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   /* 序列号 */</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    __u32 nlmsg_pid;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   /* 端口 ID (Port ID) */</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">};</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>This is Netlink&#39;s &quot;ID card.&quot; We can break these 16 bytes down into five fields:</p><ol><li><p><strong><code>nlmsg_len</code></strong>: This doesn&#39;t just refer to the data length — it&#39;s the <strong>total message length</strong>, including the header itself. When a parser reads this value, it knows exactly how many bytes to consume before moving on to the next message.</p></li><li><p><strong><code>nlmsg_type</code></strong>: This determines the purpose of the packet. There are some generic control types (less than <code>NLMSG_MIN_TYPE</code>, i.e., 0x10):</p><ul><li><strong><code>NLMSG_NOOP</code></strong>: No-op; silently ignored upon receipt.</li><li><strong><code>NLMSG_ERROR</code></strong>: Indicates an error. If the message sender requested an acknowledgment (<code>NLM_F_ACK</code>), the kernel will reply with this type when something goes wrong.</li><li><strong><code>NLMSG_DONE</code></strong>: A multi-part message terminator. Receiving this signals the end of a large message transfer.</li><li><strong><code>NLMSG_OVERRUN</code></strong>: Buffer overflow — data was lost. This is a critical error signal.</li></ul><p>But the more interesting aspect is that each specific Netlink protocol family (such as the <code>rtnetlink</code> we mentioned in the previous section) defines its own &quot;dialect&quot; within this field. For example, <code>NETLINK_ROUTE</code> defines types like <code>RTM_NEWLINK</code> (create a network interface), <code>RTM_DELLINK</code> (delete a network interface), and <code>RTM_NEWROUTE</code> (create a route). The kernel relies on this field to dispatch messages to the corresponding handler functions.</p></li><li><p><strong><code>nlmsg_flags</code></strong>: These are the &quot;behavior directives&quot; for the message. The most commonly used ones include:</p><ul><li><strong>Request and Acknowledgment</strong>: <ul><li><code>NLM_F_REQUEST</code>: Indicates that this is a request message.</li><li><code>NLM_F_ACK</code>: Requires the receiver to send back a confirmation packet. Useful for debugging, but typically disabled in production for performance reasons.</li></ul></li><li><strong>Data Dumping</strong>: <ul><li><code>NLM_F_DUMP</code>: This is critical. When you want to &quot;give me the entire routing table&quot; or &quot;give me all network interface info,&quot; you set this flag.</li><li><code>NLM_F_MULTI</code>: Used in conjunction with <code>DUMP</code>. Since the returned data volume is usually too large for a single packet, the kernel sends it in batches. All packets except the last one will carry the <code>MULTI</code> flag.</li></ul></li><li><strong>Creation and Modification</strong> (for CRUD operations): <ul><li><code>NLM_F_CREATE</code>: Create if it doesn&#39;t exist.</li><li><code>NLM_F_EXCL</code>: Return an error if it already exists (used with CREATE to implement &quot;create if not exists&quot;).</li><li><code>NLM_F_REPLACE</code>: Overwrite an existing entry.</li></ul></li></ul></li><li><p><strong><code>nlmsg_seq</code></strong>: Sequence number. This differs from TCP sequence numbers — the Netlink layer doesn&#39;t enforce continuity. Its primary purpose is to allow user-space programs to match &quot;requests&quot; with &quot;replies.&quot; If I send out sequence number 5, and the returning ACK also has sequence number 5, I know it&#39;s the response to my message.</p></li><li><p><strong><code>nlmsg_pid</code></strong>: This is the sender&#39;s &quot;port number.&quot;</p><ul><li>If the message is sent by the <strong>kernel</strong>, this field is always <strong>0</strong>.</li><li>If sent by <strong>user space</strong>, it&#39;s typically the PID (Process ID) of the sending process.</li><li>This explains how the kernel knows where to send replies — it simply copies <code>nlmsg_pid</code> as the destination address.</li></ul></li></ol><p><em>(Figure 2-3. nlmsg header shows the memory layout of these 16 bytes)</em></p><hr><h3 id="payload-and-tlv-encoding" tabindex="-1">Payload and TLV Encoding <a class="header-anchor" href="#payload-and-tlv-encoding" aria-label="Permalink to &quot;Payload and TLV Encoding&quot;">​</a></h3><p>Following the header is the payload.</p><p>We can&#39;t just shove raw data in there — that would make parsing a nightmare for the kernel. Netlink uses an extremely classic encoding format: <strong>TLV (Type-Length-Value)</strong>.</p><p>This pattern is ubiquitous in network protocols (e.g., IPv6 extension headers), and its core idea is <strong>self-description</strong>. Want to pass an IP address? No problem. A string? No problem either. As long as you specify the type and length in the header, the parser can understand it.</p><p>Preceding every Netlink attribute is a small header defined by <code>struct nlattr</code>:</p><div class="language-c vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">struct</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> nlattr {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    __u16 nla_len;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  /* 该属性的总长度（包含头部） */</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    __u16 nla_type;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> /* 属性类型 */</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">};</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><ul><li><strong><code>nla_len</code></strong>: Tells the parser how many bytes to read before skipping to the next attribute.</li><li><strong><code>nla_type</code></strong>: Defines what kind of data is contained in the attribute. <ul><li><code>NLA_U32</code>: Contains a 32-bit unsigned integer.</li><li><code>NLA_STRING</code>: Contains a string.</li><li><code>NLA_NESTED</code>: Indicates that the Value of this attribute contains yet another set of TLV structures — i.e., <strong>nested attributes</strong>. This allows us to build complex tree-like data structures.</li></ul></li></ul><p>⚠️ <strong>Warning: Alignment Issues</strong> Although the struct definition looks straightforward, in terms of memory layout, <strong>every Netlink attribute must be aligned to a 4-byte boundary</strong> (<code>NLA_ALIGNTO</code>). If you don&#39;t add padding for alignment when manually constructing packets, the kernel might silently drop them during parsing due to alignment errors, or produce garbled output.</p><hr><h3 id="attribute-validation-policy" tabindex="-1">Attribute Validation Policy <a class="header-anchor" href="#attribute-validation-policy" aria-label="Permalink to &quot;Attribute Validation Policy&quot;">​</a></h3><p>The kernel doesn&#39;t accept just anything. After receiving a Netlink message, it must verify that the attributes are valid.</p><p>Each protocol family defines an <strong>attribute validation policy</strong>, represented by an array called <code>struct nla_policy</code>. You&#39;ll notice its structure is almost identical to <code>struct nlattr</code>:</p><div class="language-c vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">struct</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> nla_policy {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    u16 type;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> /* 期望的类型，如 NLA_U32 */</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    u16 len;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  /* 期望的长度限制 */</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">};</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>This array is indexed by attribute type. When the kernel calls <code>nlmsg_parse()</code> to parse a message, it also calls <code>validate_nla()</code> (in <code>lib/nlattr.c</code>) to validate each attribute against this policy table.</p><p>The validation rules are quite detailed:</p><ul><li>For <strong>fixed-length types</strong> (like <code>NLA_U32</code>), the <code>len</code> in the policy is usually ignored since the length is predetermined.</li><li>For <strong>strings</strong> (<code>NLA_STRING</code>), <code>len</code> represents the <strong>maximum allowed length</strong> (excluding the terminating <code>\\0</code>). Strings exceeding this length are rejected.</li><li>For <strong>flags</strong> (<code>NLA_FLAG</code>), <code>len</code> is completely useless. The mere presence of this attribute means <code>true</code>, and its absence means <code>false</code> — the value itself carries no meaning.</li></ul><p><strong>Here&#39;s a gotcha</strong>: If the received attribute type exceeds the <code>maxtype</code> defined in the policy array, the kernel will <strong>silently ignore</strong> it. This is for backward compatibility — when an older kernel receives extended attributes from newer user space, it won&#39;t throw an error but will simply skip the parts it doesn&#39;t understand. However, this also means that if you find a newly added attribute isn&#39;t taking effect, first check whether you filled in the wrong <code>nla_type</code>, causing it to be discarded as an &quot;unknown extension.&quot;</p><h3 id="kernel-receive-path" tabindex="-1">Kernel Receive Path <a class="header-anchor" href="#kernel-receive-path" aria-label="Permalink to &quot;Kernel Receive Path&quot;">​</a></h3><p>Finally, let&#39;s piece these fragments together and see how the kernel processes a Generic Netlink message (the entry point is in <code>genl_rcv_msg()</code>):</p><ol><li><strong>Is it a Dump?</strong>: First, check if <code>NLM_F_DUMP</code> is present in <code>nlmsg_flags</code>. <ul><li>If yes, call <code>netlink_dump_start()</code>. This triggers the kernel to iterate over the specified table (e.g., the routing table), pack all entries, and send them back to user space.</li></ul></li><li><strong>Not a Dump? Then parse</strong>: <ul><li>Call <code>nlmsg_parse()</code>. This validates every attribute according to the <code>nla_policy</code> we just discussed.</li><li>If validation fails, the process aborts immediately and returns an error code.</li></ul></li><li><strong>Execute the operation</strong>: <ul><li>Only after validation passes does the flow continue to the next step, calling the <code>doit()</code> callback function you registered in <code>genl_ops</code>.</li></ul></li></ol><p>It&#39;s like a strict customs checkpoint: first they check your visa (the header), then they inspect your luggage (attribute validation). Only when both pass are you allowed to enter (execute the callback).</p><p>The Netlink message header and TLV mechanism form the cornerstone of the entire IPC protocol. Now that the foundation is laid, in the next section we&#39;ll start building upward — looking at what the most commonly used <code>NETLINK_ROUTE</code> messages in the networking subsystem actually look like, and how they control the routing table and network interface states.</p>`,33)])])}const g=t(a,[["render",l]]);export{u as __pageData,g as default};
